import React, { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

const Dashboard = () => {
  const [todos, setTodos] = useState([]);
  const [title, setTitle] = useState("");
  const [editId, setEditId] = useState(null);

  const userId = localStorage.getItem("userId");

  // ✅ Fetch Todos
  const fetchTodos = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5001/api/todos?userId=${userId}`
      );
      setTodos(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchTodos();
  }, []);

  // ➕ Add / Update Todo
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      if (editId) {
        await axios.put(
          `http://localhost:5001/api/todos/${editId}`,
          { title }
        );
        setEditId(null);
      } else {
        await axios.post("http://localhost:5001/api/todos", {
          userId,
          title
        });
      }

      setTitle("");
      fetchTodos();

    } catch (err) {
      console.log(err);
    }
  };

  // ❌ Delete
  const handleDelete = async (id) => {
    await axios.delete(`http://localhost:5001/api/todos/${id}`);
    fetchTodos();
  };

  // ✅ Toggle
  const handleToggle = async (id) => {
    await axios.put(
      `http://localhost:5001/api/todos/toggle/${id}`
    );
    fetchTodos();
  };

  // ✏️ Edit
  const handleEdit = (todo) => {
    setTitle(todo.title);
    setEditId(todo._id);
  };

  // 🚪 Logout
  const handleLogout = () => {
    localStorage.removeItem("userId");
    window.location.href = "/";
  };


};

export default Dashboard;
